// ─── helpers ──────────────────────────────────────────────────────────────────

function calcScore(deductions: Deductions): number {
  const total = Object.values(deductions).filter((d) => d.locked).reduce((sum, d) => sum + d.value, 0)
  return parseFloat(Math.max(0, 10 - total).toFixed(1))
}

function calcTotalDeductions(deductions: Deductions): number {
  return parseFloat(Object.values(deductions).filter((d) => d.locked).reduce((sum, d) => sum + d.value, 0).toFixed(1))
}

function isElementFullyScored(elementId: string, deductions: Deductions): boolean {
  if (!deductions[`${elementId}:1`]?.locked) return false
  for (let r = 2; r <= MAX_RETRIES + 1; r++) {
    const slot = deductions[`${elementId}:${r}`]
    if (slot !== undefined && !slot.locked) return false
  }
  return true
}

function allElementsScored(elements: TsElement[], deductions: Deductions): boolean {
  if (elements.length === 0) return true
  return elements.every((el) => isElementFullyScored(el.id, deductions))
}

function maxAttemptNumber(elementId: string, deductions: Deductions): number {
  let max = 1
  for (let r = 2; r <= MAX_RETRIES + 1; r++) {
    if (`${elementId}:${r}` in deductions) max = r
  }
  return max
}

// ─── sub-components ───────────────────────────────────────────────────────────

function PerformanceHeader({ perf, lang, score, totalDeductions }: {
  perf: Performance; lang: Lang; score: number; totalDeductions: number
}) {
  const t = T[lang]
  const routineLabel = { Balance: t.balance, Dynamic: t.dynamic, Combined: t.combined }[perf.routineType] ?? perf.routineType
  return (
    <div className="bg-slate-800 text-white px-4 py-3 rounded-xl mb-4">
      <div className="flex items-center justify-between mb-0.5">
        <span className="text-xs text-slate-400 uppercase tracking-wide font-medium">
          #{perf.position} · {perf.ageGroup} · {categoryLabel(perf.category, lang)} · {routineLabel}
        </span>
        <div className="flex items-center gap-3">
          {totalDeductions > 0 && <span className="text-xs text-red-400 tabular-nums">−{totalDeductions.toFixed(1)}</span>}
          <span className="text-xl font-bold tabular-nums">{score.toFixed(1)}</span>
        </div>
      </div>
      <p className="text-lg font-semibold leading-tight">{perf.gymnasts}</p>
    </div>
  )
}

function DeductionRow({ elementId, attemptNumber, deductions, onLock }: {
  elementId: string; attemptNumber: number; deductions: Deductions
  onLock: (elementId: string, attemptNumber: number, value: number) => void
}) {
  const key = `${elementId}:${attemptNumber}`
  const state = deductions[key]
  const isLocked = state?.locked ?? false

  return (
    <div className="flex gap-1 flex-wrap">
      {DEDUCTION_VALUES.map((val) => {
        const isSelected = isLocked && state?.value === val
        const isZero = val === 0
        return (
          <button key={val} disabled={isLocked} onClick={() => !isLocked && onLock(elementId, attemptNumber, val)}
            className={[
              'px-2 py-1.5 rounded-lg text-xs font-bold transition-all duration-150 min-w-[36px] text-center active:scale-95',
              isSelected && isZero ? 'bg-emerald-500 text-white' : '',
              isSelected && !isZero ? 'bg-red-500 text-white' : '',
              !isLocked && isZero ? 'bg-emerald-50 text-emerald-700 border border-emerald-200 hover:bg-emerald-100 cursor-pointer' : '',
              !isLocked && !isZero ? 'bg-red-50 text-red-600 border border-red-200 hover:bg-red-100 cursor-pointer' : '',
              isLocked && !isSelected ? 'bg-slate-100 text-slate-300 border border-slate-100 cursor-not-allowed' : '',
            ].join(' ')}>
            {val === 0 ? '0' : `-${val.toFixed(1).replace('0.', '.')}`}
          </button>
        )
      })}
    </div>
  )
}

function ElementRow({ element, deductions, lang, onLock, onOpenRetry, isExtra, onLabelChange }: {
  element: TsElement; deductions: Deductions; lang: Lang
  onLock: (elementId: string, attemptNumber: number, value: number) => void
  onOpenRetry: (elementId: string, nextAttemptNumber: number) => void
  isExtra?: boolean
  onLabelChange?: (id: string, label: string) => void
}) {
  const t = T[lang]
  const mainLocked = deductions[`${element.id}:1`]?.locked ?? false
  const maxAttempt = maxAttemptNumber(element.id, deductions)
  const lastAttemptLocked = deductions[`${element.id}:${maxAttempt}`]?.locked ?? false
  const canAddRetry = mainLocked && lastAttemptLocked && maxAttempt <= MAX_RETRIES

  return (
    <div className="border border-slate-100 rounded-xl p-3 bg-white">
      <div className="flex items-start gap-2 mb-2">
        <span className="text-xs text-slate-400 font-mono w-5 shrink-0 mt-0.5">{isExtra ? '✱' : element.position}</span>
        {isExtra && onLabelChange ? (
          <input type="text" value={element.label} onChange={(e) => onLabelChange(element.id, e.target.value)}
            placeholder={t.elementLabel}
            className="text-sm font-medium text-slate-700 flex-1 leading-snug border-b border-dashed border-slate-300 focus:outline-none focus:border-slate-500 bg-transparent placeholder:text-slate-300" />
        ) : (
          <span className="text-sm font-medium text-slate-700 flex-1 leading-snug">{element.label}</span>
        )}
        {!isExtra && (
          <span className="text-xs bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded font-mono shrink-0">
            {t.difficulty} {element.difficultyValue.toFixed(2)}
          </span>
        )}
      </div>

      <DeductionRow elementId={element.id} attemptNumber={1} deductions={deductions} onLock={onLock} />

      {Array.from({ length: maxAttempt - 1 }, (_, i) => i + 2).map((attempt) => (
        <div key={attempt} className="mt-2 pl-3 border-l-2 border-slate-200">
          <p className="text-xs text-slate-400 mb-1.5">{t.retry} {attempt - 1}</p>
          <DeductionRow elementId={element.id} attemptNumber={attempt} deductions={deductions} onLock={onLock} />
        </div>
      ))}

      {canAddRetry && (
        <button onClick={() => onOpenRetry(element.id, maxAttempt + 1)}
          className="mt-2 text-xs text-blue-500 hover:text-blue-700 underline underline-offset-2">
          + {t.addRetry}
        </button>
      )}
    </div>
  )
}

// ─── numeric keypad ───────────────────────────────────────────────────────────

function NumericKeypad({ lang, perf, onSubmit }: {
  lang: Lang; perf: Performance; onSubmit: (score: number) => void
}) {
  const t = T[lang]
  const [input, setInput] = useState('')
  const score = input === '' ? null : parseFloat(input)
  const isValid = score !== null && !isNaN(score) && score >= 0 && score <= 10

  function handleKey(key: string) {
    if (key === '⌫') { setInput((p) => p.slice(0, -1)); return }
    if (key === '.') {
      if (input === '' || input.includes('.')) return
      setInput((p) => p + '.'); return
    }
    const next = input + key
    if (input === '0' && key !== '.') return
    const dotIdx = next.indexOf('.')
    if (dotIdx !== -1 && next.length - dotIdx > 2) return
    const parsed = parseFloat(next)
    if (!isNaN(parsed) && parsed > 10) return
    setInput(next)
  }

  const keys = [['7','8','9'],['4','5','6'],['1','2','3'],['.','0','⌫']]

  return (
    <div className="px-4 pb-8">
      <PerformanceHeader perf={perf} lang={lang} score={isValid ? score! : 10} totalDeductions={isValid ? parseFloat((10 - score!).toFixed(1)) : 0} />
      <p className="text-xs text-slate-400 text-center mb-2">{t.scoreHint}</p>
      <div className="bg-slate-100 rounded-2xl py-5 text-center mb-4">
        <span className={['text-5xl font-bold tabular-nums tracking-tight', input ? 'text-slate-800' : 'text-slate-300'].join(' ')}>
          {input || '—'}
        </span>
      </div>
      <div className="grid grid-cols-3 gap-3 mb-4">
        {keys.flat().map((key) => (
          <button key={key} onClick={() => handleKey(key)}
            className={['py-5 rounded-2xl text-xl font-semibold transition-all active:scale-95',
              key === '⌫' ? 'bg-slate-200 text-slate-600 hover:bg-slate-300' : 'bg-white text-slate-800 shadow-sm hover:bg-slate-50 border border-slate-100'].join(' ')}>
            {key}
          </button>
        ))}
      </div>
      <button disabled={!isValid} onClick={() => isValid && onSubmit(score!)}
        className={['w-full py-4 rounded-2xl font-bold text-lg transition-all',
          isValid ? 'bg-emerald-500 hover:bg-emerald-600 active:scale-95 text-white' : 'bg-slate-100 text-slate-300 cursor-not-allowed'].join(' ')}>
        {isValid ? `${t.submit} · ${score!.toFixed(1)}` : t.submit}
      </button>
    </div>
  )
}

// ─── pdf panel ────────────────────────────────────────────────────────────────

function PdfPanel({ tsUrl, lang }: { tsUrl: string | null | undefined; lang: Lang }) {
  const t = T[lang]
  return tsUrl ? (
    <iframe src={tsUrl} className="w-full h-full rounded-2xl border border-slate-200 bg-white min-h-0" title={t.pdfPlaceholder} />
  ) : (
    <div className="w-full h-full border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center gap-3 bg-white text-slate-400 min-h-0">
      <svg className="w-12 h-12" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
        <path strokeLinecap="round" strokeLinejoin="round" d="M9 13h6M9 17h4" />
      </svg>
      <p className="font-medium">{t.pdfPlaceholder}</p>
      <p className="text-xs">{t.pdfNote}</p>
    </div>
  )
}

// ─── main component ───────────────────────────────────────────────────────────

type EJViewProps = {
  currentPerf: Performance | null
  lang: Lang
  elements: TsElement[]
  mode?: 'elements' | 'keyboard'   // default 'elements'; driven by admin config
  onSubmit?: (score: number, detail: ScoreDetail) => void
  waitingForOtherScores?: boolean
  judgeScores?: JudgeScore[]
  panelJudges?: PanelJudge[]
  result?: RoutineResult | null
  mySubmittedScore?: number | null  // non-null when this judge already scored (e.g. after refresh)
}

export default function EJView({ currentPerf, lang, elements, mode = 'elements', onSubmit, waitingForOtherScores, judgeScores, panelJudges, result, mySubmittedScore }: EJViewProps) {
  const t = T[lang]
  const [deductions, setDeductions] = useState<Deductions>({})
  // orderedAll = listed + added unlisted elements in display order
  const [orderedAll, setOrderedAll] = useState<TsElement[]>([])
  const [submitted, setSubmitted] = useState(false)
  const [submittedScore, setSubmittedScore] = useState<number | null>(null)
  // drag-drop state for unlisted elements
  const [dragId, setDragId] = useState<string | null>(null)
  const [dropIdx, setDropIdx] = useState<number | null>(null)
  const dragRef = useRef<string | null>(null)
  const prevPerfId = useRef<string | null>(null)

  useEffect(() => {
    if (currentPerf?.id !== prevPerfId.current) {
      const cacheKey = currentPerf?.id ? `scoring_ejview_${currentPerf.id}` : null
      const cached = cacheKey ? safeRead<{ deductions: Deductions; orderedAll: TsElement[] }>(cacheKey) : null
      if (cached) {
        setDeductions(cached.deductions)
        setOrderedAll(cached.orderedAll)
      } else {
        setDeductions({})
        setOrderedAll([...elements])
      }
      setSubmitted(false)
      setSubmittedScore(null)
      setDragId(null)
      setDropIdx(null)
      prevPerfId.current = currentPerf?.id ?? null
    }
  }, [currentPerf?.id, elements])

  // Restore submitted state when judge already scored (e.g. after page refresh)
  useEffect(() => {
    if (mySubmittedScore != null && !submitted) {
      setSubmitted(true)
      setSubmittedScore(mySubmittedScore)
    }
  }, [mySubmittedScore]) // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => {
    if (!currentPerf?.id || submitted) return
    safeWrite(`scoring_ejview_${currentPerf.id}`, { deductions, orderedAll })
  }, [deductions, orderedAll, currentPerf?.id, submitted])

  function handleLock(elementId: string, attemptNumber: number, value: number) {
    setDeductions((prev) => ({ ...prev, [`${elementId}:${attemptNumber}`]: { value, locked: true } }))
  }

  function handleOpenRetry(elementId: string, nextAttemptNumber: number) {
    setDeductions((prev) => ({ ...prev, [`${elementId}:${nextAttemptNumber}`]: { value: 0, locked: false } }))
  }

  function handleAddElement() {
    const id = `extra-${Date.now()}`
    setOrderedAll((prev) => [...prev, { id, position: 0, label: '', difficultyValue: 0 }])
  }

  function handleLabelChange(id: string, label: string) {
    setOrderedAll((prev) => prev.map((el) => el.id === id ? { ...el, label } : el))
  }

  function handleReorder(draggedId: string, targetIdx: number) {
    setOrderedAll((prev) => {
      const dragged = prev.find((e) => e.id === draggedId)
      if (!dragged) return prev
      const without = prev.filter((e) => e.id !== draggedId)
      without.splice(targetIdx, 0, dragged)
      return without
    })
    setDragId(null)
    setDropIdx(null)
  }

  function handleSubmitElements() {
    const score = calcScore(deductions)
    const extraElements = orderedAll.filter(el => !elements.some(e => e.id === el.id))
    setSubmittedScore(score)
    setSubmitted(true)
    if (currentPerf?.id) localStorage.removeItem(`scoring_ejview_${currentPerf.id}`)
    onSubmit?.(score, { ejDeductions: deductions, ejExtraElements: extraElements })
  }

  function handleSubmitPhone(score: number) {
    const extraElements = orderedAll.filter(el => !elements.some(e => e.id === el.id))
    setSubmittedScore(score)
    setSubmitted(true)
    if (currentPerf?.id) localStorage.removeItem(`scoring_ejview_${currentPerf.id}`)
    onSubmit?.(score, { ejDeductions: deductions, ejExtraElements: extraElements })
  }

  // ── waiting ──
  if (!currentPerf) {
    return (
      <div className="flex flex-col items-center justify-center flex-1 text-center px-6 gap-4">
        <div className="w-16 h-16 rounded-full bg-slate-100 flex items-center justify-center">
          <svg className="w-8 h-8 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6l4 2m6-2a10 10 0 11-20 0 10 10 0 0120 0z" />
          </svg>
        </div>
        <p className="text-xl font-semibold text-slate-700">{t.waiting}</p>
        <p className="text-sm text-slate-400">{t.waitingSub}</p>
      </div>
    )
  }

  // ── submitted ──
  if (submitted && submittedScore !== null) {
    return (
      <div className="flex-1 min-h-0 overflow-y-auto px-4 py-8 space-y-6 max-w-lg mx-auto">
        <div className="flex flex-col items-center text-center gap-3">
          <div className="w-16 h-16 rounded-full bg-emerald-100 flex items-center justify-center">
            <svg className="w-8 h-8 text-emerald-500" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
            </svg>
          </div>
          <p className="text-slate-500 font-medium uppercase tracking-wide text-sm">{t.submitted}</p>
          <p className="text-6xl font-bold text-slate-800">{submittedScore.toFixed(1)}</p>
        </div>
        {waitingForOtherScores && (
          <div className="flex items-center justify-center gap-2 text-slate-400">
            <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M4 4v5h5M20 20v-5h-5M4 9a9 9 0 0114.65-3.65L20 7M4 17l1.35 1.65A9 9 0 0020 15" />
            </svg>
            <p className="text-sm">{t.waitingOtherScores}</p>
          </div>
        )}
        {judgeScores && panelJudges && (
          <ScoreGrid scores={judgeScores} panelJudges={panelJudges} lang={lang} locked={true} result={result} onReopen={() => {}} />
        )}
      </div>
    )
  }

  const score = calcScore(deductions)
  const totalDed = calcTotalDeductions(deductions)
  const canSubmit = allElementsScored(orderedAll, deductions)

  // ── keyboard mode: keypad view, PDF alongside on wide screens ──
  if (mode === 'keyboard') {
    return (
      <div className="flex-1 min-h-0 flex flex-col md:flex-row">
        {/* narrow: keypad scrolls naturally */}
        <div className="md:hidden overflow-y-auto">
          <NumericKeypad lang={lang} perf={currentPerf} onSubmit={handleSubmitPhone} />
        </div>
        {/* wide: PDF + keypad side by side */}
        <div className="hidden md:flex gap-4 flex-1 min-h-0 px-4 pb-4">
          <div className="flex-1 min-h-0">
            <PdfPanel tsUrl={currentPerf.tsUrl} lang={lang} />
          </div>
          <div className="w-[400px] overflow-y-auto">
            <NumericKeypad lang={lang} perf={currentPerf} onSubmit={handleSubmitPhone} />
          </div>
        </div>
      </div>
    )
  }

  // ── elements mode: element list always visible, PDF alongside on wide screens ──
  return (
    <div className="px-4 pb-4 md:flex-1 md:min-h-0 md:flex md:flex-col">
      <div className="md:flex md:gap-4 md:flex-1 md:min-h-0">
        {/* PDF: md+ only */}
        <div className="hidden md:flex flex-1 flex-col min-h-0">
          <PdfPanel tsUrl={currentPerf.tsUrl} lang={lang} />
        </div>

        {/* element list: always visible, full width on narrow */}
        <div className="md:flex-none md:w-96 md:flex md:flex-col md:gap-3 md:min-h-0 flex flex-col gap-3">
          <PerformanceHeader perf={currentPerf} lang={lang} score={score} totalDeductions={totalDed} />

          <div className="space-y-2 pr-1 md:flex-1 md:overflow-y-auto md:min-h-0">
            {orderedAll.length === 0 ? (
              <div className="text-center py-8 text-slate-400">
                <p className="font-medium text-sm">{t.noElements}</p>
                <p className="text-xs mt-1">{t.noElementsNote}</p>
              </div>
            ) : (
              orderedAll.map((el, idx) => {
                const isExtra = el.id.startsWith('extra-')
                const isDragging = dragId === el.id
                const isDropTarget = dragId && !isDragging && dropIdx === idx
                return (
                  <div
                    key={el.id}
                    draggable={isExtra}
                    onDragStart={isExtra ? (e) => { e.dataTransfer.effectAllowed = 'move'; dragRef.current = el.id; setDragId(el.id) } : undefined}
                    onDragEnd={() => { dragRef.current = null; setDragId(null); setDropIdx(null) }}
                    onDragOver={(e) => { e.preventDefault(); if (dragRef.current) setDropIdx(idx) }}
                    onDrop={(e) => { e.preventDefault(); if (dragRef.current) handleReorder(dragRef.current, idx) }}
                    className={[
                      isExtra ? 'cursor-grab active:cursor-grabbing' : '',
                      isDragging ? 'opacity-40' : '',
                      isDropTarget ? 'ring-2 ring-blue-400 ring-offset-1 rounded-xl' : '',
                    ].join(' ')}
                  >
                    {isExtra && <div className="text-xs text-slate-300 text-right pr-1 mb-0.5 select-none">⠿ drag to reorder</div>}
                    <ElementRow element={el} deductions={deductions} lang={lang}
                      onLock={handleLock} onOpenRetry={handleOpenRetry}
                      isExtra={isExtra}
                      onLabelChange={isExtra ? handleLabelChange : undefined} />
                  </div>
                )
              })
            )}

            {/* drop zone at end of list */}
            {dragId && (
              <div
                className={['h-2 rounded-lg transition-all', dropIdx === orderedAll.length ? 'bg-blue-400' : ''].join(' ')}
                onDragOver={(e) => { e.preventDefault(); setDropIdx(orderedAll.length) }}
                onDrop={(e) => { e.preventDefault(); if (dragRef.current) handleReorder(dragRef.current, orderedAll.length) }}
              />
            )}

            <button onClick={handleAddElement}
              className="w-full py-2.5 rounded-xl text-sm text-slate-400 hover:text-slate-600 border border-dashed border-slate-200 hover:border-slate-300 transition-all">
              {t.addElement}
            </button>
          </div>

          <button disabled={!canSubmit} onClick={handleSubmitElements}
            className={['w-full py-4 rounded-2xl font-bold text-lg transition-all shrink-0',
              canSubmit ? 'bg-emerald-500 hover:bg-emerald-600 active:scale-95 text-white' : 'bg-slate-100 text-slate-300 cursor-not-allowed'].join(' ')}>
            {canSubmit ? `${t.submit} · ${score.toFixed(1)}` : t.submit}
          </button>
        </div>
      </div>
    </div>
  )
}
